1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const LOYALTY_DISCOUNT = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const FOLLOW_UP_CONTRACT_DISCOUNT = 0.15;
6	const FLOAT_ROUNDING_TOLERANCE = 1e-9;
7	const BLOCK_OF_THREE_DISCOUNT = 15;
8	
9	const BASE_PREMIUM: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const INSURANCE_VALUE: Record<string, number> = {
19	  sword: 1000,
20	  amulet: 600,
21	  staff: 800,
22	  potion: 400,
23	  rune: 250,
24	  moonstone: 250,
25	};
26	
27	const CAP_MULTIPLIER = 2;
28	
29	type Item = { type: string; cursed?: boolean; enchantment?: number };
30	type QuoteStep = { op: "quote"; items: Array<Item> };
31	type Damage = { itemType: string; amount: number };
32	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<Damage> } };
33	type Step = QuoteStep | ClaimStep;
34	type Customer = { yearsWithMHPCO: number };
35	type Scenario = {
36	  customer: Customer;
37	  steps: Array<Step>;
38	};
39	
40	const roundDownInMHPCOFavor = (amount: number): number =>
41	  Math.floor(amount + FLOAT_ROUNDING_TOLERANCE);
42	
43	const roundUpInMHPCOFavor = (amount: number): number =>
44	  Math.ceil(amount - FLOAT_ROUNDING_TOLERANCE);
45	
46	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
47	
48	const HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
49	
50	type ItemSurcharge = { applies: (item: Item) => boolean; rate: number };
51	
52	const ITEM_SURCHARGES: Array<ItemSurcharge> = [
53	  { applies: (item) => item.cursed === true, rate: 0.5 },
54	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_SURCHARGE_THRESHOLD, rate: 0.3 },
55	];
56	
57	const surchargesFor = (item: Item): number =>
58	  ITEM_SURCHARGES.reduce(
59	    (sum, { applies, rate }) => sum + (applies(item) ? basePremiumOf(item) * rate : 0),
60	    0,
61	  );
62	
63	const sumOfBasePrices = (items: Array<Item>): number =>
64	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
65	
66	const sumOfItemSurcharges = (items: Array<Item>): number =>
67	  items.reduce((sum, item) => sum + surchargesFor(item), 0);
68	
69	const COMPONENT_TYPES = ["rune", "moonstone"];
70	const BLOCK_SIZE = 3;
71	
72	const countOfType = (items: Array<Item>, type: string): number =>
73	  items.filter((item) => item.type === type).length;
74	
75	const formsABlock = (items: Array<Item>, type: string): boolean =>
76	  countOfType(items, type) === BLOCK_SIZE;
77	
78	const blockDiscountFor = (items: Array<Item>): number =>
79	  COMPONENT_TYPES.filter((type) => formsABlock(items, type)).length *
80	  BLOCK_OF_THREE_DISCOUNT;
81	
82	const basePremiumFor = (items: Array<Item>): number =>
83	  sumOfBasePrices(items) - blockDiscountFor(items);
84	
85	type PolicyContext = { customer: Customer; isFollowUp: boolean };
86	type PolicyAdjustment = { applies: (ctx: PolicyContext) => boolean; signedRate: number };
87	
88	const POLICY_ADJUSTMENTS: Array<PolicyAdjustment> = [
89	  { applies: () => true, signedRate: +FIRST_INSURANCE_SURCHARGE },
90	  { applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, signedRate: -LOYALTY_DISCOUNT },
91	  { applies: ({ isFollowUp }) => isFollowUp, signedRate: -FOLLOW_UP_CONTRACT_DISCOUNT },
92	];
93	
94	const policyAdjustmentsOn = (policyBase: number, ctx: PolicyContext): number =>
95	  POLICY_ADJUSTMENTS.reduce(
96	    (sum, { applies, signedRate }) => sum + (applies(ctx) ? policyBase * signedRate : 0),
97	    0,
98	  );
99	
100	const quoteStep = (step: QuoteStep, ctx: PolicyContext): { premium: number } => {
101	  const policyBase = basePremiumFor(step.items);
102	  const premiumBeforeRounding =
103	    policyBase
104	    + policyAdjustmentsOn(policyBase, ctx)
105	    + sumOfItemSurcharges(step.items)
106	    + PROCESSING_FEE;
107	  return { premium: roundUpInMHPCOFavor(premiumBeforeRounding) };
108	};
109	
110	const DEDUCTIBLE = 100;
111	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
112	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
113	
114	const findInsuredItem = (policy: QuoteStep, itemType: string): Item =>
115	  policy.items.find((item) => item.type === itemType)!;
116	
117	const reimbursementOf = (item: Item, damage: Damage): number =>
118	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
119	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
120	    : damage.amount;
121	
122	const payoutForDamage = (item: Item, damage: Damage): number =>
123	  reimbursementOf(item, damage) - DEDUCTIBLE;
124	
125	const capFor = (policy: QuoteStep): number =>
126	  CAP_MULTIPLIER * policy.items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
127	
128	const claimStep = (step: ClaimStep, policy: QuoteStep): { payout: number; remainingCap: number } => {
129	  const payoutBeforeRounding = step.incident.damages.reduce(
130	    (sum, damage) => sum + payoutForDamage(findInsuredItem(policy, damage.itemType), damage),
131	    0,
132	  );
133	  const payout = roundDownInMHPCOFavor(payoutBeforeRounding);
134	  return { payout, remainingCap: capFor(policy) - payout };
135	};
136	
137	const isQuoteStep = (step: Step): step is QuoteStep => step.op === "quote";
138	
139	export const processScenario = (scenario: unknown): unknown => {
140	  const { customer, steps } = scenario as Scenario;
141	  const results = steps.map((step, index) => {
142	    if (isQuoteStep(step)) {
143	      return quoteStep(step, { customer, isFollowUp: index > 0 });
144	    }
145	    return claimStep(step, steps[step.policy] as QuoteStep);
146	  });
147	  return { results };
148	};
